SELECT TABLE_NAME, COLUMN_NAME, COUNT(CONSTRAINT_NAME) FROM ALL_CONS_COLUMNS WHERE OWNER = 'PARRANDEROS' AND TABLE_NAME = 'BARES' AND COLUMN_NAME = 'ID' GROUP BY TABLE_NAME, COLUMN_NAME;
SELECT TABLE_NAME, COLUMN_NAME, COUNT(CONSTRAINT_NAME) FROM ALL_CONS_COLUMNS WHERE OWNER = 'PARRANDEROS' AND TABLE_NAME = 'BEBEDORES' AND COLUMN_NAME = 'ID' GROUP BY TABLE_NAME, COLUMN_NAME;
SELECT TABLE_NAME, COLUMN_NAME, COUNT(CONSTRAINT_NAME) FROM ALL_CONS_COLUMNS WHERE OWNER = 'PARRANDEROS' AND TABLE_NAME = 'BEBIDAS' AND COLUMN_NAME = 'ID' GROUP BY TABLE_NAME, COLUMN_NAME;
SELECT TABLE_NAME, COLUMN_NAME, COUNT(CONSTRAINT_NAME) FROM ALL_CONS_COLUMNS WHERE OWNER = 'PARRANDEROS' AND TABLE_NAME = 'BEBIDAS' AND COLUMN_NAME = 'TIPO' GROUP BY TABLE_NAME, COLUMN_NAME;
SELECT TABLE_NAME, COLUMN_NAME, COUNT(CONSTRAINT_NAME) FROM ALL_CONS_COLUMNS WHERE OWNER = 'PARRANDEROS' AND TABLE_NAME = 'TIPO_BEBIDA' AND COLUMN_NAME = 'ID' GROUP BY TABLE_NAME, COLUMN_NAME;